mapper.update:
UPDATE inbound
type=#{type}, quantity=#{quantity}, unit_price=#{unitPrice}, total_amount=#{totalAmount}, supplier=#{supplier}, remark=#{remark}, status=#{status},
WHERE id=#{id}

mapper.select:
SELECT * FROM inbound


        AND id = #{id}


        AND inbound_no LIKE CONCAT('%', #{inboundNo}, '%')


        AND type = #{type}


        AND material_id = #{materialId}


        AND warehouse_id = #{warehouseId}


        AND operator_id = #{operatorId}


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


ORDER BY created_at DESC
